import { Device, DeviceCapabilities } from './Device.js';
import type { PrecisionClock } from '@psyforge/timing';

export interface AudioDeviceInfo {
  deviceId: string;
  label: string;
  kind: MediaDeviceKind;
  groupId: string;
}

export interface AudioEventData {
  level?: number;
  frequency?: number;
  duration?: number;
  buffer?: ArrayBuffer;
}

export class AudioDevice extends Device {
  private audioContext?: AudioContext;
  private mediaStream?: MediaStream;
  private analyser?: AnalyserNode;
  private microphone?: MediaStreamAudioSourceNode;
  private outputNode?: AudioDestinationNode;
  private isRecording: boolean = false;
  private deviceChangeHandler: () => void;
  private monitoringFrameId?: number;
  private cleanupPromise?: Promise<void>;
  private isCleaningUp = false;
  private finalizationRegistry?: FinalizationRegistry<() => void>;

  constructor(clock: PrecisionClock) {
    const capabilities: DeviceCapabilities = {
      canDetectHotplug: true,
      supportsHighPrecisionTiming: true,
      maxSampleRate: 48000,
      supportedFormats: ['audio/wav', 'audio/webm', 'audio/ogg'],
    };

    super('audio-primary', 'audio', capabilities, clock);

    // Bind event handler to maintain correct reference for removal
    this.deviceChangeHandler = this.handleDeviceChange.bind(this);

    // Set up finalizer for automatic cleanup if not explicitly called
    if (typeof FinalizationRegistry !== 'undefined') {
      const cleanup = () => {
        if (!this.isCleaningUp) {
          console.warn('AudioDevice garbage collected without explicit cleanup - performing emergency cleanup');
          this.cleanup().catch(err => console.error('Emergency cleanup failed:', err));
        }
      };

      // Create a FinalizationRegistry to clean up if the object is GC'd
      this.finalizationRegistry = new FinalizationRegistry(cleanup);
      this.finalizationRegistry.register(this, cleanup);
    }
  }

  async initialize(): Promise<void> {
    if (this._isConnected) {
      return;
    }

    try {
      // Create audio context
      this.audioContext = new (window.AudioContext ||
        (window as any).webkitAudioContext)();

      // Resume context if suspended (required for some browsers)
      if (this.audioContext.state === 'suspended') {
        await this.audioContext.resume();
      }

      this.outputNode = this.audioContext.destination;
      this.setConnected(true);

      // Monitor device changes
      navigator.mediaDevices?.addEventListener(
        'devicechange',
        this.deviceChangeHandler,
      );
    } catch (error) {
      throw new Error(`Failed to initialize audio device: ${error}`);
    }
  }

  async cleanup(): Promise<void> {
    // Prevent multiple concurrent cleanups
    if (this.isCleaningUp) {
      return this.cleanupPromise;
    }

    this.isCleaningUp = true;
    this.cleanupPromise = this.performCleanup();

    try {
      await this.cleanupPromise;
    } finally {
      this.isCleaningUp = false;
    }
  }

  private async performCleanup(): Promise<void> {
    // First stop recording to prevent any new listeners from being added
    await this.stopRecording();

    // Cancel any pending animation frames immediately
    if (this.monitoringFrameId) {
      cancelAnimationFrame(this.monitoringFrameId);
      this.monitoringFrameId = undefined;
    }

    // Stop and clean up media stream tracks
    if (this.mediaStream) {
      try {
        this.mediaStream.getTracks().forEach((track) => {
          if (track.readyState !== 'ended') {
            track.stop();
          }
        });
      } catch (error) {
        console.warn('Error stopping media stream tracks:', error);
      }
      this.mediaStream = undefined;
    }

    // Properly disconnect audio nodes before closing context
    if (this.microphone) {
      try {
        this.microphone.disconnect();
      } catch (error) {
        // Node may already be disconnected, ignore error
      }
      this.microphone = undefined;
    }

    if (this.analyser) {
      try {
        this.analyser.disconnect();
      } catch (error) {
        // Node may already be disconnected, ignore error
      }
      this.analyser = undefined;
    }

    // Close audio context with proper error handling
    if (this.audioContext && this.audioContext.state !== 'closed') {
      try {
        await this.audioContext.close();
      } catch (error) {
        console.warn('Error closing audio context:', error);
      }
      this.audioContext = undefined;
    }

    // Remove event listener using correct reference (defensive check)
    if (navigator.mediaDevices && this.deviceChangeHandler) {
      try {
        navigator.mediaDevices.removeEventListener(
          'devicechange',
          this.deviceChangeHandler,
        );
      } catch (error) {
        console.warn('Error removing device change listener:', error);
      }
    }

    this.outputNode = undefined;
    this.isRecording = false;
    this.setConnected(false);
  }

  async detectCapabilities(): Promise<DeviceCapabilities> {
    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
      return {
        canDetectHotplug: false,
        supportsHighPrecisionTiming: false,
        maxSampleRate: 0,
        supportedFormats: [],
      };
    }

    const devices = await this.getAudioDevices();
    // TODO: Use hasInput/hasOutput for more specific capability detection
    devices.some((d) => d.kind === 'audioinput');
    devices.some((d) => d.kind === 'audiooutput');

    return {
      canDetectHotplug: true,
      supportsHighPrecisionTiming: true,
      maxSampleRate: this.audioContext?.sampleRate || 48000,
      supportedFormats: ['audio/wav', 'audio/webm', 'audio/ogg'],
    };
  }

  async getAudioDevices(): Promise<AudioDeviceInfo[]> {
    if (!navigator.mediaDevices || !navigator.mediaDevices.enumerateDevices) {
      return [];
    }

    try {
      const devices = await navigator.mediaDevices.enumerateDevices();
      return devices
        .filter(
          (device) =>
            device.kind === 'audioinput' || device.kind === 'audiooutput',
        )
        .map((device) => ({
          deviceId: device.deviceId,
          label: device.label,
          kind: device.kind,
          groupId: device.groupId,
        }));
    } catch (error) {
      console.error('Error enumerating audio devices:', error);
      return [];
    }
  }

  async startRecording(deviceId?: string): Promise<void> {
    if (this.isRecording) {
      return;
    }

    if (!this.audioContext) {
      throw new Error('Audio context not initialized');
    }

    try {
      const constraints: MediaStreamConstraints = {
        audio: deviceId ? { deviceId: { exact: deviceId } } : true,
      };

      this.mediaStream = await navigator.mediaDevices.getUserMedia(constraints);
      this.microphone = this.audioContext.createMediaStreamSource(
        this.mediaStream,
      );

      // Create analyser for audio level monitoring
      this.analyser = this.audioContext.createAnalyser();
      this.analyser.fftSize = 256;
      this.microphone.connect(this.analyser);

      this.isRecording = true;
      this.emitEvent('recordingstarted', { started: true });

      // Start monitoring audio levels
      this.monitorAudioLevel();
    } catch (error) {
      throw new Error(`Failed to start recording: ${error}`);
    }
  }

  async stopRecording(): Promise<void> {
    if (!this.isRecording) {
      return;
    }

    // Set flag first to prevent race conditions
    this.isRecording = false;

    // Cancel animation frame monitoring with defensive check
    if (this.monitoringFrameId) {
      try {
        cancelAnimationFrame(this.monitoringFrameId);
      } catch (error) {
        console.warn('Error cancelling animation frame:', error);
      }
      this.monitoringFrameId = undefined;
    }

    // Stop media stream tracks
    if (this.mediaStream) {
      try {
        this.mediaStream.getTracks().forEach((track) => {
          if (track.readyState !== 'ended') {
            track.stop();
          }
        });
      } catch (error) {
        console.warn('Error stopping media stream tracks during recording stop:', error);
      }
    }

    // Disconnect microphone node
    if (this.microphone) {
      try {
        this.microphone.disconnect();
      } catch (error) {
        console.warn('Error disconnecting microphone node:', error);
      }
    }

    this.emitEvent('recordingstopped', { stopped: true });
  }

  async playSound(buffer: ArrayBuffer, volume: number = 1.0): Promise<void> {
    if (!this.audioContext || !this.outputNode) {
      throw new Error('Audio context not initialized');
    }

    try {
      const audioBuffer = await this.audioContext.decodeAudioData(
        buffer.slice(0),
      );
      const source = this.audioContext.createBufferSource();
      const gainNode = this.audioContext.createGain();

      source.buffer = audioBuffer;
      gainNode.gain.value = Math.max(0, Math.min(1, volume));

      source.connect(gainNode);
      gainNode.connect(this.outputNode);

      const startTime = this.audioContext.currentTime;

      // Clean up nodes after sound finishes with proper error handling
      const cleanup = () => {
        try {
          source.disconnect();
          gainNode.disconnect();
        } catch (error) {
          // Ignore errors during cleanup - nodes may already be disconnected
        }
      };

      source.addEventListener('ended', cleanup);

      // Ensure cleanup happens even if source fails to start
      source.addEventListener('error', cleanup);

      // Set up timeout cleanup as fallback
      const timeoutId = setTimeout(() => {
        cleanup();
        source.removeEventListener('ended', cleanup);
        source.removeEventListener('error', cleanup);
      }, (audioBuffer.duration + 1) * 1000); // 1 second buffer

      // Override cleanup to also clear timeout
      const originalCleanup = cleanup;
      const enhancedCleanup = () => {
        clearTimeout(timeoutId);
        originalCleanup();
        source.removeEventListener('ended', enhancedCleanup);
        source.removeEventListener('error', enhancedCleanup);
      };

      source.removeEventListener('ended', cleanup);
      source.removeEventListener('error', cleanup);
      source.addEventListener('ended', enhancedCleanup);
      source.addEventListener('error', enhancedCleanup);

      source.start(startTime);

      this.emitEvent('soundplayed', {
        duration: audioBuffer.duration,
        startTime: this.clock.now(),
      });
    } catch (error) {
      throw new Error(`Failed to play sound: ${error}`);
    }
  }

  async createTone(
    frequency: number,
    duration: number,
    volume: number = 0.5,
  ): Promise<void> {
    if (!this.audioContext || !this.outputNode) {
      throw new Error('Audio context not initialized');
    }

    const oscillator = this.audioContext.createOscillator();
    const gainNode = this.audioContext.createGain();

    oscillator.frequency.value = frequency;
    oscillator.type = 'sine';

    gainNode.gain.value = 0;
    gainNode.gain.setValueAtTime(0, this.audioContext.currentTime);
    gainNode.gain.linearRampToValueAtTime(
      volume,
      this.audioContext.currentTime + 0.01,
    );
    gainNode.gain.linearRampToValueAtTime(
      0,
      this.audioContext.currentTime + duration - 0.01,
    );

    oscillator.connect(gainNode);
    gainNode.connect(this.outputNode);

    const startTime = this.audioContext.currentTime;

    // Clean up nodes after tone finishes with proper error handling
    const cleanup = () => {
      try {
        oscillator.disconnect();
        gainNode.disconnect();
      } catch (error) {
        // Ignore errors during cleanup - nodes may already be disconnected
      }
    };

    oscillator.addEventListener('ended', cleanup);

    // Ensure cleanup happens even if oscillator fails to start
    oscillator.addEventListener('error', cleanup);

    // Set up timeout cleanup as fallback
    const timeoutId = setTimeout(() => {
      cleanup();
      oscillator.removeEventListener('ended', cleanup);
      oscillator.removeEventListener('error', cleanup);
    }, (duration + 1) * 1000); // 1 second buffer

    // Override cleanup to also clear timeout
    const originalCleanup = cleanup;
    const enhancedCleanup = () => {
      clearTimeout(timeoutId);
      originalCleanup();
      oscillator.removeEventListener('ended', enhancedCleanup);
      oscillator.removeEventListener('error', enhancedCleanup);
    };

    oscillator.removeEventListener('ended', cleanup);
    oscillator.removeEventListener('error', cleanup);
    oscillator.addEventListener('ended', enhancedCleanup);
    oscillator.addEventListener('error', enhancedCleanup);

    oscillator.start(startTime);
    oscillator.stop(startTime + duration);

    this.emitEvent('toneplayed', {
      frequency,
      duration,
      startTime: this.clock.now(),
    });
  }

  private monitorAudioLevel(): void {
    if (!this.analyser || !this.isRecording) {
      if (this.monitoringFrameId) {
        cancelAnimationFrame(this.monitoringFrameId);
        this.monitoringFrameId = undefined;
      }
      return;
    }

    try {
      const dataArray = new Uint8Array(this.analyser.frequencyBinCount);
      this.analyser.getByteFrequencyData(dataArray);

      const average = dataArray.reduce((a, b) => a + b) / dataArray.length;
      const level = average / 255;

      this.emitEvent('audiolevel', { level });

      if (this.isRecording) {
        this.monitoringFrameId = requestAnimationFrame(() => this.monitorAudioLevel());
      } else {
        if (this.monitoringFrameId) {
          cancelAnimationFrame(this.monitoringFrameId);
          this.monitoringFrameId = undefined;
        }
      }
    } catch (error) {
      // If monitoring fails, stop monitoring to prevent memory leaks
      console.warn('Audio level monitoring failed:', error);
      if (this.monitoringFrameId) {
        cancelAnimationFrame(this.monitoringFrameId);
        this.monitoringFrameId = undefined;
      }
    }
  }

  private handleDeviceChange(): void {
    this.emitEvent('devicechange', { changed: true });
  }

  get currentTime(): number {
    return this.audioContext?.currentTime || 0;
  }

  get sampleRate(): number {
    return this.audioContext?.sampleRate || 0;
  }
}

