    40→
    41→export class ConsentManager {
    42→  private consentResults: Map<string, ConsentResult> = new Map();
    43→  private static instance: ConsentManager;
    44→
    45→  private constructor() {}
    46→
    47→  static getInstance(): ConsentManager {
    48→    if (!ConsentManager.instance) {
    49→      ConsentManager.instance = new ConsentManager();
    50→    }
    51→    return ConsentManager.instance;
    52→  }
    53→
    54→  /**
    55→   * Request consent from participant
    56→   */
    57→  async requestConsent(
    58→    sessionId: string,
    59→    options: ConsentOptions,
    60→    participantId?: string
    61→  ): Promise<ConsentResult> {
    62→    // Check if consent already granted for this session
    63→    const existingConsent = this.consentResults.get(sessionId);
    64→    if (existingConsent && existingConsent.granted) {
    65→      return existingConsent;
    66→    }
    67→
    68→    // Create consent UI
    69→    const consentResult = await this.showConsentDialog(options);
    70→    
    71→    // Store consent result
    72→    const result: ConsentResult = {
    73→      granted: consentResult,
    74→      timestamp: Date.now(),
    75→      options,
    76→      participantId,
    77→      sessionId,
    78→    };
    79→
    80→    this.consentResults.set(sessionId, result);
    81→    
    82→    // Log consent decision for compliance
    83→    console.log(`Consent ${result.granted ? 'granted' : 'denied'} for session ${sessionId}`, {
    84→      timestamp: new Date(result.timestamp).toISOString(),
    85→      purpose: options.purpose,
    86→      dataTypes: options.dataTypes,
    87→      participantId,
    88→    });
    89→
    90→    return result;
    91→  }
    92→
    93→  /**
    94→   * Get consent status for a session
    95→   */
    96→  getConsentStatus(sessionId: string): ConsentResult | null {
    97→    return this.consentResults.get(sessionId) || null;
    98→  }
    99→
   100→  /**
   101→   * Check if consent is granted for a session
   102→   */
   103→  hasConsent(sessionId: string): boolean {
   104→    const result = this.consentResults.get(sessionId);
   105→    return result?.granted || false;
   106→  }
   107→
   108→  /**
   109→   * Revoke consent for a session
   110→   */
   111→  revokeConsent(sessionId: string): void {
   112→    const result = this.consentResults.get(sessionId);
   113→    if (result) {
   114→      result.granted = false;
   115→      result.timestamp = Date.now();
   116→      console.log(`Consent revoked for session ${sessionId}`);
   117→    }
   118→  }
   119→
   120→  /**
   121→   * Get all consent records (for data audit purposes)
   122→   */
   123→  getAllConsentRecords(): ConsentResult[] {
   124→    return Array.from(this.consentResults.values());
   125→  }
   126→
   127→  /**
   128→   * Clear expired consent records
   129→   */
   130→  clearExpiredConsent(maxAge: number = 24 * 60 * 60 * 1000): void {
   131→    const now = Date.now();
   132→    for (const [sessionId, result] of this.consentResults.entries()) {
   133→      if (now - result.timestamp > maxAge) {
   134→        this.consentResults.delete(sessionId);
   135→      }
   136→    }
   137→  }
   138→
   139→  /**
   140→   * Show consent dialog to user
   141→   */
   142→  private async showConsentDialog(options: ConsentOptions): Promise<boolean> {
   143→    return new Promise((resolve) => {
   144→      // Create modal backdrop
   145→      const backdrop = document.createElement('div');
