   147→        position: fixed;
   148→        top: 0;
   149→        left: 0;
   150→        width: 100%;
   151→        height: 100%;
   152→        background-color: rgba(0, 0, 0, 0.5);
   153→        display: flex;
   154→        align-items: center;
   155→        justify-content: center;
   156→        z-index: 10000;
   157→        font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
   158→      `;
   159→
   160→      // Create modal dialog
   161→      const dialog = document.createElement('div');
   162→      dialog.style.cssText = `
   163→        background: white;
   164→        border-radius: 8px;
   165→        padding: 24px;
   166→        max-width: 600px;
   167→        max-height: 80vh;
   168→        overflow-y: auto;
   169→        box-shadow: 0 4px 20px rgba(0, 0, 0, 0.15);
   170→        margin: 20px;
   171→      `;
   172→
   173→      // Create content
