   196→        ${options.storageDuration ? `<p><strong>Storage Duration:</strong> ${this.escapeHtml(options.storageDuration)}</p>` : ''}
   197→        ${options.contactInfo?.email ? `<p><strong>Contact:</strong> ${this.escapeHtml(options.contactInfo.email)}</p>` : ''}
   198→        ${sanitizedPrivacyUrl ? `<p><a href="${sanitizedPrivacyUrl}" target="_blank" rel="noopener noreferrer">View Privacy Policy</a></p>` : ''}
   199→        <p>Do you consent to this data collection?</p>
   200→      `;
   201→
   202→      message.innerHTML = options.customMessage ? this.escapeHtml(options.customMessage) : defaultMessage;
   203→
   204→      // Create buttons
   205→      const buttonContainer = document.createElement('div');
   206→      buttonContainer.style.cssText = `
   207→        display: flex;
