   219→        border-radius: 4px;
   220→        cursor: pointer;
   221→        font-size: 14px;
   222→        font-weight: 500;
   223→      `;
   224→      denyButton.textContent = 'Deny';
   225→      denyButton.onclick = () => {
   226→        document.body.removeChild(backdrop);
   227→        resolve(false);
