import { z } from 'zod';
import type { TimelineItem, TimelineContext } from '../core/Timeline.js';
import { 
  sanitizeColorValue, 
  sanitizeFontFamily, 
  sanitizeClassName, 
  sanitizeStyleValue, 
  sanitizeTextContent, 
  sanitizeNumericValue 
} from '../utils/security.js';
import { timestampToNumber, timestampDiff } from '../utils/timing.js';

export interface TextStimulusOptions {
  duration?: number;
  position?: { x: number; y: number };
  fontSize?: number;
  fontFamily?: string;
  color?: string;
  backgroundColor?: string;
  opacity?: number;
  rotation?: number;
  scale?: number;
  zIndex?: number;
  className?: string;
  style?: Record<string, string>;
  metadata?: Record<string, unknown>;
}

export class TextStimulus implements TimelineItem {
  public readonly id: string;
  private textContent: string | ((context: TimelineContext) => string);
  private options: TextStimulusOptions;
  private element?: HTMLElement;

  constructor(
    id: string,
    text: string | ((context: TimelineContext) => string),
    options: TextStimulusOptions = {}
  ) {
    this.id = id;
    this.textContent = text;
    this.options = options;
  }

  text(content: string | ((context: TimelineContext) => string)): this {
    this.textContent = content;
    return this;
  }

  setDuration(ms: number): this {
    this.options.duration = ms;
    return this;
  }

  position(x: number, y: number): this {
    this.options.position = { x, y };
    return this;
  }

  fontSize(size: number): this {
    this.options.fontSize = size;
    return this;
  }

  fontFamily(family: string): this {
    const sanitized = sanitizeFontFamily(family);
    if (sanitized) {
      this.options.fontFamily = sanitized;
    }
    return this;
  }

  color(textColor: string): this {
    const sanitized = sanitizeColorValue(textColor);
    if (sanitized) {
      this.options.color = sanitized;
    }
    return this;
  }

  backgroundColor(bgColor: string): this {
    const sanitized = sanitizeColorValue(bgColor);
    if (sanitized) {
      this.options.backgroundColor = sanitized;
    }
    return this;
  }

  opacity(alpha: number): this {
    this.options.opacity = Math.max(0, Math.min(1, alpha));
    return this;
  }

  rotation(degrees: number): this {
    this.options.rotation = degrees;
    return this;
  }

  scale(factor: number): this {
    this.options.scale = factor;
    return this;
  }

  zIndex(z: number): this {
    this.options.zIndex = z;
    return this;
  }

  className(name: string): this {
    const sanitized = sanitizeClassName(name);
    if (sanitized) {
      this.options.className = sanitized;
    }
    return this;
  }

  style(styles: Record<string, string>): this {
    const sanitizedStyles: Record<string, string> = {};

    for (const [property, value] of Object.entries(styles)) {
      const sanitizedValue = sanitizeStyleValue(property, value);
      if (sanitizedValue) {
        sanitizedStyles[property] = sanitizedValue;
      }
    }

    this.options.style = { ...this.options.style, ...sanitizedStyles };
    return this;
  }

  setMetadata(data: Record<string, unknown>): this {
    this.options.metadata = data;
    return this;
  }

  private createTextElement(context: TimelineContext): HTMLElement {
    const element = document.createElement('div');

    // Set text content with sanitization
    const text = typeof this.textContent === 'function' 
      ? this.textContent(context) 
      : this.textContent;
    element.textContent = sanitizeTextContent(text);

    // Apply basic styles
    element.style.position = 'absolute';
    element.style.pointerEvents = 'none';

    // Apply position
    if (this.options.position) {
      element.style.left = `${this.options.position.x}px`;
      element.style.top = `${this.options.position.y}px`;
    } else {
      // Center by default
      element.style.left = '50%';
      element.style.top = '50%';
      element.style.transform = 'translate(-50%, -50%)';
    }

    // Apply text styling with sanitization
    if (this.options.fontSize) {
      const sanitizedSize = sanitizeNumericValue(this.options.fontSize, 1, 1000);
      if (sanitizedSize) {
        element.style.fontSize = `${sanitizedSize}px`;
      }
    }
    if (this.options.fontFamily) {
      const sanitizedFamily = sanitizeFontFamily(this.options.fontFamily);
      if (sanitizedFamily) {
        element.style.fontFamily = sanitizedFamily;
      }
    }
    if (this.options.color) {
      const sanitizedColor = sanitizeColorValue(this.options.color);
      if (sanitizedColor) {
        element.style.color = sanitizedColor;
      }
    }
    if (this.options.backgroundColor) {
      const sanitizedBgColor = sanitizeColorValue(this.options.backgroundColor);
      if (sanitizedBgColor) {
        element.style.backgroundColor = sanitizedBgColor;
      }
    }
    if (this.options.opacity !== undefined) {
      element.style.opacity = this.options.opacity.toString();
    }
    if (this.options.rotation !== undefined) {
      const currentTransform = element.style.transform || '';
      element.style.transform = `${currentTransform} rotate(${this.options.rotation}deg)`;
    }
    if (this.options.scale !== undefined) {
      const currentTransform = element.style.transform || '';
      element.style.transform = `${currentTransform} scale(${this.options.scale})`;
    }
    if (this.options.zIndex !== undefined) {
      element.style.zIndex = this.options.zIndex.toString();
    }

    // Apply CSS class
    if (this.options.className) {
      element.className = this.options.className;
    }

    // Apply custom styles with sanitization
    if (this.options.style) {
      for (const [property, value] of Object.entries(this.options.style)) {
        const sanitizedValue = sanitizeStyleValue(property, value);
        if (sanitizedValue) {
          (element.style as any)[property] = sanitizedValue;
        }
      }
    }

    return element;
  }

  async execute(context: TimelineContext): Promise<void> {
    const startTime = timestampToNumber(context.clock.now());

    // Create and display element
    this.element = this.createTextElement(context);
    document.body.appendChild(this.element);

    // Wait for duration if specified
    if (this.options.duration) {
      return new Promise((resolve) => {
        const checkTime = () => {
          const elapsed = timestampDiff(context.clock.now(), startTime);
          if (elapsed >= this.options.duration!) {
            this.cleanup();
            resolve();
          } else {
            requestAnimationFrame(checkTime);
          }
        };
        checkTime();
      });
    }
  }

  private cleanup(): void {
    if (this.element && this.element.parentNode) {
      this.element.parentNode.removeChild(this.element);
      this.element = undefined;
    }
  }

  hide(): void {
    this.cleanup();
  }

  serialize(): Record<string, unknown> {
    return {
      type: 'TextStimulus',
      id: this.id,
      text: typeof this.textContent === 'string' ? this.textContent : '[Function]',
      options: {
        ...this.options,
        // Remove non-serializable style object for now
        style: undefined,
      },
    };
  }

  static deserialize(data: Record<string, unknown>): TextStimulus {
    const schema = z.object({
      id: z.string(),
      text: z.string(),
      options: z.object({
        duration: z.number().optional(),
        position: z.object({ x: z.number(), y: z.number() }).optional(),
        fontSize: z.number().optional(),
        fontFamily: z.string().optional(),
        color: z.string().optional(),
        backgroundColor: z.string().optional(),
        opacity: z.number().optional(),
        rotation: z.number().optional(),
        scale: z.number().optional(),
        zIndex: z.number().optional(),
        className: z.string().optional(),
        metadata: z.record(z.unknown()).optional(),
      }).optional(),
    });

    const parsed = schema.parse(data);
    return new TextStimulus(parsed.id, parsed.text, parsed.options);
  }

  get duration(): number | undefined {
    return this.options.duration;
  }

  get metadata(): Record<string, unknown> | undefined {
    return this.options.metadata;
  }
}

